class Base(DeclarativeBase): pass

class Item(Base):
    __tablename__ = "items"
    id: Mapped[int] = mapped_column(primary_key=True)
    name: Mapped[str] = mapped_column(String(100))
    description: Mapped[Optional[str]] = mapped_column(String(500), default=None)
    price: Mapped[float] = mapped_column(default=0.0)

# --- Pydantic schemas (Pydantic v2) ---
class ItemCreate(BaseModel):
    name: str
    description: str | None = None
    price: float = 0.0

class ItemUpdate(BaseModel):
    name: str | None = None
    description: str | None = None
    price: float | None = None

class ItemRead(BaseModel):
    id: int
    name: str
    description: str | None = None
    price: float

    model_config = ConfigDict(from_attributes=True)  # Pydantic v2 ORM mode

# --- CRUD functions ---
def create_item(db: Session, data: ItemCreate) -> Item:
    item = Item(**data.model_dump())
    db.add(item)
    db.commit()
    db.refresh(item)
    return item

def get_item(db: Session, item_id: int) -> Item | None:
    return db.get(Item, item_id)

def get_items(db: Session, skip: int = 0, limit: int = 100) -> list[Item]:
    return db.query(Item).offset(skip).limit(limit).all()

def update_item(db: Session, item_id: int, data: ItemUpdate) -> Item | None:
    item = db.get(Item, item_id)
    if not item:
        return None
    update_data = data.model_dump(exclude_unset=True)  # only fields that were sent
    for field, value in update_data.items():
        setattr(item, field, value)
    db.commit()
    db.refresh(item)
    return item

def delete_item(db: Session, item_id: int) -> bool:
    item = db.get(Item, item_id)
    if not item:
        return False
    db.delete(item)
    db.commit()
    return True

