    db = SessionLocal()
    try:
        yield db
    finally:
        db.close()

DbDep = Annotated[Session, Depends(get_db)]

app = FastAPI()

# Helper: base query that excludes soft-deleted records
def active_articles():
    return select(Article).where(Article.deleted_at.is_(None))

# List only active articles
@app.get("/articles")
def list_articles(
    db: DbDep,
    include_deleted: Annotated[bool, Query()] = False,
):
    if include_deleted:
        stmt = select(Article)
    else:
        stmt = active_articles()
    return db.execute(stmt).scalars().all()

# Get a single article (only if active)
@app.get("/articles/{article_id}")
def get_article(article_id: int, db: DbDep):
    article = db.get(Article, article_id)
    if not article or article.is_deleted:
        raise HTTPException(status_code=404, detail="Article not found")
    return article

# Soft delete
@app.delete("/articles/{article_id}", status_code=204)
def delete_article(article_id: int, db: DbDep):
    article = db.get(Article, article_id)
    if not article or article.is_deleted:
        raise HTTPException(status_code=404, detail="Article not found")
    article.soft_delete()
    db.commit()

# Restore
@app.post("/articles/{article_id}/restore")
def restore_article(article_id: int, db: DbDep):
    article = db.get(Article, article_id)
    if not article:
        raise HTTPException(status_code=404, detail="Article not found")
    if not article.is_deleted:
        raise HTTPException(status_code=400, detail="Article is not deleted")
    article.restore()
    db.commit()
    return {"id": article.id, "title": article.title, "restored": True}

# Hard delete (admin only -- permanently removes the record)
@app.delete("/admin/articles/{article_id}/purge", status_code=204)
def purge_article(article_id: int, db: DbDep):
    article = db.get(Article, article_id)
    if not article:
        raise HTTPException(status_code=404, detail="Article not found")
    db.delete(article)
    db.commit()

